export const qbMerchProblemSolving = [
  { "FABM1-MerchBusActgPCQ-001": { "subject": "FABM1", "topic": "Accounting for Merchandising Business", "subtopic": "Cash Discount", "type": "Problem Solving", "competency": "Apply", "question": "Goods were purchased for ₱20,000 with terms 2/10, n/30. If payment is made within the discount period, how much is paid?", "solution": 19600, "explanation": "Original Invoice: ₱20,000 * (1 - (Discount Rate: 0.02)) = Amount Paid: ₱19,600" } },
  { "FABM1-MerchBusActgPCQ-002": { "subject": "FABM1", "topic": "Accounting for Merchandising Business", "subtopic": "Cash Discount", "type": "Problem Solving", "competency": "Apply", "question": "Purchased goods for ₱50,000, terms 2/10, n/30. Returned ₱5,000 worth of defective goods before payment. If paid within the discount period, calculate the amount paid.", "solution": 44100, "explanation": "Initial Purchase: ₱50,000 - Purchase Returns: 5,000 = Net Purchase: ₱45,000 * (1 - (Discount Rate: 0.02)): 0.98 = Amount Paid: ₱44,100" } },
  { "FABM1-MerchBusActgPCQ-003": { "subject": "FABM1", "topic": "Accounting for Merchandising Business", "subtopic": "Cost of Goods Sold", "type": "Problem Solving", "competency": "Apply", "question": "Beginning Inventory: ₱10,000. Net Purchases: ₱40,000. Ending Inventory: ₱12,000. Calculate Cost of Goods Sold.", "solution": 38000, "explanation": "Beginning Inventory: ₱10,000 + Net Purchases: 40,000 - Ending Inventory: 12,000 = Cost of Goods Sold: ₱38,000" } },
  { "FABM1-MerchBusActgPCQ-004": { "subject": "FABM1", "topic": "Accounting for Merchandising Business", "subtopic": "Cost of Goods Sold", "type": "Problem Solving", "competency": "Analyze", "question": "Cost of Goods Available for Sale is ₱100,000. Cost of Goods Sold is ₱70,000. What is the value of Ending Inventory?", "solution": 30000, "explanation": "Total Goods Available for Sale: ₱100,000 - Ending Inventory (X):  = Cost of Goods Sold: ₱70,000. To find for X. Total Goods Available for Sale: ₱100,000 - Cost of Goods sold: 70,000 = Ending Inventory Value: ₱30,000." } },
  { "FABM1-MerchBusActgPCQ-005": { "subject": "FABM1", "topic": "Accounting for Merchandising Business", "subtopic": "FIFO Costing", "type": "Problem Solving", "competency": "Apply", "question": "Beginning Inventory: 10 units @ 10 PHP. Purchased: 20 units @ 12 PHP. Sold: 15 units. Calculate the value of Ending Inventory using FIFO.", "solution": 180, "explanation": "Beginning units: 10 + Purchased units: 20 - Sold units: 15 = Remaining units: 15. Under FIFO, ending inventory comes from the latest purchases: Remaining units: 15 * Latest Unit Cost per unit:  ₱12 = Ending Inventory Value:  ₱180" } },
  { "FABM1-MerchBusActgPCQ-006": { "subject": "FABM1", "topic": "Accounting for Merchandising Business", "subtopic": "FIFO Costing", "type": "Problem Solving", "competency": "Apply", "question": "Beginning Inventory: 10 units @ 10 PHP. Purchased: 20 units @ 12 PHP. Sold: 15 units. Calculate COGS using FIFO.", "solution": 160, "explanation": "Sold 15 units. FIFO uses beginning inventory first (10 units * ₱10): ₱100 + Remaining 5 from purchase from first purchase (5 units * 12):  60 = Total COGS: ₱160" } },
  { "FABM1-MerchBusActgPCQ-007": { "subject": "FABM1", "topic": "Accounting for Merchandising Business", "subtopic": "Freight In", "type": "Problem Solving", "competency": "Apply", "question": "Purchases are 80,000 PHP, Purchase Returns 2,000 PHP, Purchase Discounts 1,000 PHP, and Freight In 500 PHP. Calculate Net Cost of Purchases.", "solution": 77500, "explanation": "Purchases:  ₱80,000 - Purchase Returns:  ₱2,000 - Purchase Discounts:  ₱1,000 + Freight In:  ₱500 = Net Cost of Purchases:  ₱77,500" } },
  { "FABM1-MerchBusActgPCQ-008": { "subject": "FABM1", "topic": "Accounting for Merchandising Business", "subtopic": "Freight Out", "type": "Problem Solving", "competency": "Analyze", "question": "A seller sold goods FOB Destination. The shipping cost was 1,500 PHP. The goods cost 10,000 PHP and were sold for 15,000 PHP. What amount is recorded as Freight Out expense?", "solution": 1500, "explanation": "FOB Destination means seller pays freight. Selling paid freight is selling or delivery expense that is usually called Freight Out." } },
  { "FABM1-MerchBusActgPCQ-009": { "subject": "FABM1", "topic": "Accounting for Merchandising Business", "subtopic": "Merchandising Operations", "type": "Problem Solving", "competency": "Apply", "question": "Net Sales are 200,000 PHP and Cost of Goods Sold is 120,000 PHP. Calculate Gross Profit.", "solution": 80000, "explanation": "Net Sales:  ₱200,000 - Cost of Goods Sold:  ₱120,000 = Gross Profit:  ₱80,000" } },
  { "FABM1-MerchBusActgPCQ-010": { "subject": "FABM1", "topic": "Accounting for Merchandising Business", "subtopic": "Merchandising Operations", "type": "Problem Solving", "competency": "Apply", "question": "Gross Profit is 60,000 PHP. Operating Expenses are 25,000 PHP. Calculate Net Income.", "solution": 35000, "explanation": "Gross Profit:  ₱60,000 - Operating Expenses:  ₱25,000 = Net Income:  ₱35,000" } },
  { "FABM1-MerchBusActgPCQ-011": { "subject": "FABM1", "topic": "Accounting for Merchandising Business", "subtopic": "Moving Average Costing", "type": "Problem Solving", "competency": "Apply", "question": "Jan 1 Balance: 10 units @ 20 PHP. Jan 5 Purchase: 10 units @ 24 PHP. Calculate the new moving average unit cost after Jan 5 purchase.", "solution": 22, "explanation": "Jan 1 purchase (10 units @ P20 per unit):  ₱200 + Jan 5 purchase (10 units @ P24 per unit):  ₱240 = Total Value:  ₱440 / Total Units (Jan 1 purchase: 10 units + Jan 5 purchase: 10 units): 20 = Moving Average Cost per unit:  ₱22" } },
  { "FABM1-MerchBusActgPCQ-012": { "subject": "FABM1", "topic": "Accounting for Merchandising Business", "subtopic": "Net Sales", "type": "Problem Solving", "competency": "Apply", "question": "Gross Sales are 150,000 PHP. Sales Returns are 5,000 PHP and Sales Discounts are 2,000 PHP. Calculate Net Sales.", "solution": 143000, "explanation": "Gross Sales:  ₱150,000 - Sales Returns:  ₱5,000 - Sales Discounts:  ₱2,000 = Net Sales:  ₱143,000" } },
  { "FABM1-MerchBusActgPCQ-013": { "subject": "FABM1", "topic": "Accounting for Merchandising Business", "subtopic": "Periodic Inventory System", "type": "Problem Solving", "competency": "Apply", "question": "Beginning Inventory is  ₱5,000. Purchases are  ₱25,000. Freight In is  ₱1,000. Purchase Returns are  ₱2,000. Calculate Cost of Goods Available for Sale.", "solution": 29000, "explanation": "Beginning Inventory:  ₱5,000 + Purchases:  ₱25,000 + Freight In:  ₱1,000 - Purchase Returns:  ₱2,000 = Cost of Goods Available for Sale:  ₱29,000" } },
  { "FABM1-MerchBusActgPCQ-014": { "subject": "FABM1", "topic": "Accounting for Merchandising Business", "subtopic": "Perpetual Inventory System", "type": "Problem Solving", "competency": "Analyze", "question": "Inventory record shows a balance of  ₱50,000. Physical count shows  ₱48,500. Calculate the amount of inventory shrinkage/shortage.", "solution": 1500, "explanation": "Recorded Inventory Balance:  ₱50,000 - Physical Count Balance:  ₱48,500 = Inventory Shrinkage:  ₱1,500" } },
  { "FABM1-MerchBusActgPCQ-015": { "subject": "FABM1", "topic": "Accounting for Merchandising Business", "subtopic": "Purchase Returns", "type": "Problem Solving", "competency": "Apply", "question": "A company bought goods for  ₱10,000 on credit. They returned 1,500 worth of goods. What is the remaining Accounts Payable balance?", "solution": 8500, "explanation": "Original Purchase on Credit:  ₱10,000 - Returned Goods Value:  ₱1,500 = Remaining Accounts Payable:  ₱8,500" } },
  { "FABM1-MerchBusActgPCQ-016": { "subject": "FABM1", "topic": "Accounting for Merchandising Business", "subtopic": "Sales Returns", "type": "Problem Solving", "competency": "Apply", "question": "Sold goods for  ₱100,000 on account. Customer returned  ₱10,000 worth of goods. Subsequently, the customer paid the balance within the discount period of 2%. Calculate the cash received.", "solution": 88200, "explanation": "Receivable balance: Original Sale:  ₱100,000 - Sales Returns:  ₱10,000 = Net Receivable:  ₱90,000 - Discount (Net Receivable: 90,000) * (Discount Rate: 0.02):  ₱1,800 = Cash Received:  ₱88,200" } },
  { "FABM1-MerchBusActgPCQ-017": { "subject": "FABM1", "topic": "Accounting for Merchandising Business", "subtopic": "Trade Discount", "type": "Problem Solving", "competency": "Apply", "question": "A merchandiser buys an item with a list price of  ₱50,000 subject to a 20% trade discount. Calculate the invoice price.", "solution": 40000, "explanation": "List Price:  ₱50,000 * (1 - (Trade Discount Rate: 0.20)): 0.80 = Invoice Price:  ₱40,000" } },
  { "FABM1-MerchBusActgPCQ-018": { "subject": "FABM1", "topic": "Accounting for Merchandising Business", "subtopic": "Trade Discount", "type": "Problem Solving", "competency": "Apply", "question": "A list price of  ₱100,000 is subject to trade discounts of 20% and 10%. Calculate the net invoice price.", "solution": 72000, "explanation": "List Price:  ₱100,000 * (1 - (First Trade Discount: 0.20)): 0.80 = Price after First Discount:  ₱80,000 * (1 - (Second Trade Discount: 0.10)): 0.90 = Net Invoice Price: ₱72,000" } },
  { "FABM1-MerchBusActgPCQ-019": { "subject": "FABM1", "topic": "Accounting for Merchandising Business", "subtopic": "Weighted Average Costing", "type": "Problem Solving", "competency": "Apply", "question": "Beginning Inv: 100 units @ ₱10. Purchase: 100 units @ ₱14. Calculate the weighted average unit cost.", "solution": 12, "explanation": "Beginning Inventory (100 units @ ₱10 per unit): P1,000 + Purchase (100 units * ₱14 per unit): ₱1,400 = Total Cost: ₱2,400 / Total units (100 beginning units + 100 purcahsed units): 200 = Weighted Average Cost: ₱12" } },
  { "FABM1-MerchBusActgPCQ-020": { "subject": "FABM1", "topic": "Accounting for Merchandising Business", "subtopic": "Weighted Average Costing", "type": "Problem Solving", "competency": "Apply", "question": "Using the weighted average cost of ₱12 per unit, if 150 units are sold, calculate the Cost of Goods Sold.", "solution": 1800, "explanation": "Sold units: 150 * Weighted Average Cost: ₱12 = Cost of Goods Sold: ₱1,800" } },

  { "FAR-CashAndCashEq-001": { "subject": "FAR", "topic": "Cash and Cash Equivalents", "subtopic": "Classification of Cash Equivalents", "type": "Problem Solving", "competency": "Apply", "question": "Tranvia Company had the following balances on December 31, 2023: Cash in checking account ₱350,000; Cash in money market account ₱750,000; Treasury bill, purchased November 1, 2023 maturing January 31, 2024: ₱3,500,000; Time deposit purchased December 1, 2023 maturing March 31, 2024: ₱4,000,000. What amount should be reported as cash and cash equivalents on December 31, 2023?", "solution": 4600000, "explanation": "Cash in checking account: ₱350,000 + Cash in money market account: 750,000 + Treasury bill (three month term): 3,500,000 = Total cash and cash equivalents: ₱4,600,000. Under PAS 7, the time deposit is excluded from cash equivalents because its term is four months from December 1 to March 31, which exceeds the strict short maturity requirement of three months or less from the date of acquisition. The Treasury bill is included because it matures within exactly three months from its purchase date." } },
  { "FAR-CashAndCashEq-002": { "subject": "FAR", "topic": "Cash and Cash Equivalents", "subtopic": "Bank Overdrafts and Restrictions", "type": "Problem Solving", "competency": "Analyze", "question": "A company reported the following: Cash in bank Bank A Checking ₱500,000; Cash in bank Bank A Savings ₱200,000; Cash in bank Bank B Checking overdraft ₱100,000; Legally restricted compensating balance in Bank C ₱150,000; Cash on hand ₱50,000. What is the total cash and cash equivalents?", "solution": 750000, "explanation": "Cash in bank Bank A Checking: ₱500,000 + Cash in bank Bank A Savings: 200,000 + Cash on hand: 50,000 = Total cash and cash equivalents: ₱750,000. The overdraft in Bank B is excluded and reported as a current liability because overdrafts cannot be offset against positive balances in different banks due to the lack of mutual creditor and debtor relationships. The legally restricted compensating balance is excluded from cash because it is legally frozen as collateral and is not available for general business use." } },
  { "FAR-CashAndCashEq-003": { "subject": "FAR", "topic": "Cash and Cash Equivalents", "subtopic": "Adjustments to Cash Balance", "type": "Problem Solving", "competency": "Apply", "question": "The unadjusted cash balance of ₱1,500,000 includes the following: Customer postdated check ₱100,000; Customer NSF check ₱50,000; Unreleased company check ₱150,000; Company check postdated to next year ₱200,000. Calculate the adjusted cash balance.", "solution": 1700000, "explanation": "Unadjusted cash balance: ₱1,500,000 - Customer postdated check: 100,000 - Customer NSF check: 50,000 + Unreleased company check: 150,000 + Postdated company check: 200,000 = Adjusted cash balance: ₱1,700,000. Customer postdated and NSF checks are deducted because they are not valid cash collections and must revert to receivables. The unreleased company check is added back to cash because the payment is not consummated until physical delivery to the payee. The postdated company check is added back because the check cannot be validly encashed by the payee until the future date." } },
  { "FAR-CashAndCashEq-004": { "subject": "FAR", "topic": "Cash and Cash Equivalents", "subtopic": "Petty Cash Fund", "type": "Problem Solving", "competency": "Apply", "question": "The petty cash fund has a ledger balance of ₱20,000. A count reveals: Bills and coins ₱5,000; Employee IOUs ₱3,000; Unreplenished vouchers for supplies ₱10,000; Replenishment check drawn to the custodian ₱2,000. What is the correct petty cash balance?", "solution": 7000, "explanation": "Bills and coins: ₱5,000 + Replenishment check: 2,000 = Correct petty cash fund: ₱7,000. IOUs are excluded from cash because they are essentially advances or receivables from employees. Unreplenished vouchers are excluded because they represent expenses that have already been paid out from the fund and simply await formal recording." } },
  { "FAR-CashAndCashEq-005": { "subject": "FAR", "topic": "Cash and Cash Equivalents", "subtopic": "Short Term Investments", "type": "Problem Solving", "competency": "Analyze", "question": "Evaluate these investments: 90 day treasury bill ₱1,000,000; 180 day treasury bill purchased 30 days before maturity ₱500,000; 1 year treasury bill purchased 3 months before maturity ₱800,000; Equity securities purchased to sell in 2 months ₱600,000. Calculate the total cash equivalents.", "solution": 2300000, "explanation": "90 day treasury bill: ₱1,000,000 + 180 day treasury bill purchased 30 days before maturity: 500,000 + 1 year treasury bill purchased 3 months before maturity: 800,000 = Total cash equivalents: ₱2,300,000. Equity securities are completely excluded from cash equivalents, regardless of how soon they will be sold, because they represent ownership rather than debt and inherently lack a fixed maturity date." } },
  { "FAR-CashAndCashEq-006": { "subject": "FAR", "topic": "Cash and Cash Equivalents", "subtopic": "Cash on Hand Components", "type": "Problem Solving", "competency": "Apply", "question": "A company cash on hand includes: Currency and coins ₱120,000; Postal stamps ₱2,000; Travel advances ₱15,000; Manager check ₱30,000; Traveler check ₱40,000. Compute the correct cash on hand.", "solution": 190000, "explanation": "Currency and coins: ₱120,000 + Manager check: 30,000 + Traveler check: 40,000 = Correct cash on hand: ₱190,000. Postal stamps are excluded because they are physical goods classified as prepaid office supplies. Travel advances are excluded because they represent a future liquidation of expenses or receivables from traveling employees." } },
  { "FAR-CashAndCashEq-007": { "subject": "FAR", "topic": "Cash and Cash Equivalents", "subtopic": "Foreign Currency and Time Deposits", "type": "Problem Solving", "competency": "Apply", "question": "A firm has a Checking account ₱800,000; Unrestricted foreign bank account ₱1,200,000; Restricted foreign bank account ₱500,000; and a 60 day Time deposit ₱400,000. Compute the total cash and cash equivalents.", "solution": 2400000, "explanation": "Checking account: ₱800,000 + Unrestricted foreign bank account: 1,200,000 + 60 day time deposit: 400,000 = Total cash and cash equivalents: ₱2,400,000. The restricted foreign bank account is excluded from the current cash balance because restrictions block the company from freely utilizing the funds to settle current operating obligations." } },
  { "FAR-CashAndCashEq-008": { "subject": "FAR", "topic": "Cash and Cash Equivalents", "subtopic": "Compensating Balances", "type": "Problem Solving", "competency": "Analyze", "question": "An unadjusted cash balance of ₱3,000,000 includes a legally restricted compensating balance of ₱400,000 and an informal unrestricted compensating balance of ₱200,000. A 3 month money market placement of ₱600,000 is not yet recorded. What is the correct cash and cash equivalents?", "solution": 3200000, "explanation": "Unadjusted cash balance: ₱3,000,000 - Legally restricted compensating balance: 400,000 + 3 month money market placement: 600,000 = Correct cash and cash equivalents: ₱3,200,000. The legally restricted compensating balance is deducted because it serves as blocked collateral for a loan. The informal compensating balance remains part of cash because there is no binding legal agreement preventing its withdrawal." } },
  { "FAR-CashAndCashEq-009": { "subject": "FAR", "topic": "Cash and Cash Equivalents", "subtopic": "Restricted Funds", "type": "Problem Solving", "competency": "Analyze", "question": "Determine cash and cash equivalents given the following: Cash on hand ₱100,000; Cash in bank ₱900,000; Sinking fund cash ₱400,000; Cash in escrow ₱250,000; 60 day commercial paper ₱350,000.", "solution": 1350000, "explanation": "Cash on hand: ₱100,000 + Cash in bank: 900,000 + 60 day commercial paper: 350,000 = Total cash and cash equivalents: ₱1,350,000. Sinking fund cash is excluded because it is earmarked specifically for retiring noncurrent debt. Cash in escrow is excluded because its release is strictly tied to the completion of a pending contract or condition." } },
  { "FAR-CashAndCashEq-010": { "subject": "FAR", "topic": "Cash and Cash Equivalents", "subtopic": "Adjusted Bank Balance", "type": "Problem Solving", "competency": "Apply", "question": "The balance per bank statement is ₱1,200,000. Deposits in transit are ₱300,000. Outstanding checks amount to ₱450,000. A bank error incorrectly charged the company account for ₱50,000. Calculate the adjusted cash in bank balance.", "solution": 1100000, "explanation": "Balance per bank: ₱1,200,000 + Deposits in transit: 300,000 - Outstanding checks: 450,000 + Bank error erroneous charge: 50,000 = Adjusted cash in bank: ₱1,100,000. The erroneous bank charge is added back because the bank wrongfully deducted it from the company account, so correcting the bank balance requires restoring the improperly charged amount." } },
  { "FAR-CashAndCashEq-011": { "subject": "FAR", "topic": "Cash and Cash Equivalents", "subtopic": "Classification of Cash Equivalents", "type": "Problem Solving", "competency": "Analyze", "question": "On December 31, a company has: Cash in bank ₱2,000,000; 120 day treasury bill purchased December 1 ₱500,000; 90 day time deposit ₱400,000; 180 day commercial paper purchased November 1 ₱600,000. Calculate total cash and cash equivalents.", "solution": 2400000, "explanation": "Cash in bank: ₱2,000,000 + 90 day time deposit: 400,000 = Total cash and cash equivalents: ₱2,400,000. The 120 day treasury bill and 180 day commercial paper are excluded because their original maturity strictly measured from the date of acquisition exceeds the permissible maximum of three months." } },
  { "FAR-CashAndCashEq-012": { "subject": "FAR", "topic": "Cash and Cash Equivalents", "subtopic": "Cash Count Valuation", "type": "Problem Solving", "competency": "Apply", "question": "A cash count reveals: Coins and currency ₱22,000; Checks payable to company ₱15,000 containing a ₱5,000 postdated check; Stamps ₱1,000; IOUs from employees ₱4,000. Calculate the total cash on hand.", "solution": 320000, "explanation": "Coins and currency: ₱22,000 + Valid checks on hand: 10,000 = Total cash on hand: ₱32,000. The postdated check is excluded because it cannot be deposited or cashed until the specified future date. Stamps and IOUs are excluded because they represent office supplies and receivables, respectively." } },
  { "FAR-CashAndCashEq-013": { "subject": "FAR", "topic": "Cash and Cash Equivalents", "subtopic": "Checkbook Adjustments", "type": "Problem Solving", "competency": "Apply", "question": "The checkbook balance is ₱4,000,000. It includes: a check payable to a supplier for ₱200,000 drawn and recorded but not yet mailed; a check for ₱150,000 dated January 15 of next year drawn and recorded. Compute the adjusted cash in bank.", "solution": 4350000, "explanation": "Checkbook balance: ₱4,000,000 + Undelivered check: 200,000 + Postdated company check: 150,000 = Adjusted cash in bank: ₱4,350,000. The undelivered check is added back because the underlying payment requires physical delivery to the payee to be considered complete. The postdated check is added back because it is not negotiable by the supplier until the following year." } },
  { "FAR-CashAndCashEq-014": { "subject": "FAR", "topic": "Cash and Cash Equivalents", "subtopic": "Bank Overdrafts Offsetting", "type": "Problem Solving", "competency": "Analyze", "question": "A company has the following bank accounts: Cash in bank First Bank ₱1,500,000; Cash in bank Second Bank overdraft ₱200,000; Cash in bank Third Bank ₱800,000; Cash in bank Third Bank overdraft ₱100,000. What is the total reportable cash in bank?", "solution": 2200000, "explanation": "Cash in bank First Bank: ₱1,500,000 + Net cash in Third Bank: 700,000 = Total cash in bank: ₱2,200,000. The overdraft in Second Bank is treated as a liability because it cannot be offset against First Bank. The overdraft in Third Bank is offset against the positive balance in Third Bank because legal compensation and the right of setoff naturally exist between accounts in the same bank." } },
  { "FAR-CashAndCashEq-015": { "subject": "FAR", "topic": "Cash and Cash Equivalents", "subtopic": "Window Dressing Adjustments", "type": "Problem Solving", "competency": "Apply", "question": "The cash ledger shows ₱3,500,000. This includes January collections of ₱300,000 improperly recorded as December receipts. Also, a check of ₱100,000 in payment of accounts payable was recorded in December but actually mailed in January. Calculate the adjusted cash balance.", "solution": 3300000, "explanation": "Unadjusted cash balance: ₱3,500,000 - January collections recorded in December: 300,000 + Undelivered check: 100,000 = Adjusted cash balance: ₱3,300,000. January collections are deducted because they belong to the subsequent reporting period and artificially inflate the current cash balance. The undelivered check is added back because cash has not legally changed hands." } },
  { "FAR-CashAndCashEq-016": { "subject": "FAR", "topic": "Cash and Cash Equivalents", "subtopic": "Classification of Specific Funds", "type": "Problem Solving", "competency": "Analyze", "question": "The cash account balance of ₱5,000,000 includes: Plant expansion fund ₱1,000,000; Dividend fund ₱500,000; Payroll fund ₱300,000; Pension fund ₱400,000. Only the plant expansion fund is reserved for a noncurrent asset. Compute cash and cash equivalents.", "solution": 4000000, "explanation": "Total cash account: ₱5,000,000 - Plant expansion fund: 1,000,000 = Cash and cash equivalents: ₱4,000,000. Funds set aside for the payment of current operating liabilities like dividends and payroll remain classified as current cash. The plant expansion fund is excluded because it is earmarked for noncurrent asset acquisitions." } },
  { "FAR-CashAndCashEq-017": { "subject": "FAR", "topic": "Cash and Cash Equivalents", "subtopic": "Reconciliation to Adjusted Balance", "type": "Problem Solving", "competency": "Apply", "question": "The balance per ledger is ₱2,000,000. The bank service charge is ₱10,000. A note collected by the bank is ₱250,000. An NSF check amounts to ₱40,000. Outstanding checks are ₱300,000. What is the adjusted cash balance?", "solution": 2200000, "explanation": "Balance per ledger: ₱2,000,000 + Note collected by bank: 250,000 - Bank service charge: 10,000 - NSF check: 40,000 = Adjusted cash balance: ₱2,200,000. Outstanding checks are completely ignored in this calculation because they are reconciling items that adjust the bank statement balance, not the internal ledger balance." } },
  { "FAR-CashAndCashEq-018": { "subject": "FAR", "topic": "Cash and Cash Equivalents", "subtopic": "Foreign Currency Translation", "type": "Problem Solving", "competency": "Apply", "question": "An unadjusted cash balance of ₱4,000,000 includes a US Dollar account of 50,000 dollars originally recorded at ₱50 per dollar. The exchange rate on December 31 is ₱55 per dollar. What is the adjusted cash balance?", "solution": 4250000, "explanation": "Unadjusted cash balance: ₱4,000,000 + Foreign exchange gain on translation: 250,000 = Adjusted cash balance: ₱4,250,000. Foreign currency bank accounts are monetary assets that must be restated using the closing exchange rate at the reporting date, yielding an unrealized foreign exchange gain." } },
  { "FAR-CashAndCashEq-019": { "subject": "FAR", "topic": "Cash and Cash Equivalents", "subtopic": "Equity and Noncurrent Distractors", "type": "Problem Solving", "competency": "Analyze", "question": "The accounting records show: Cash in checking account ₱1,200,000; Cash in savings account ₱800,000; Treasury shares ₱300,000; Bond sinking fund ₱500,000. Compute total cash and cash equivalents.", "solution": 2000000, "explanation": "Cash in checking account: ₱1,200,000 + Cash in savings account: 800,000 = Total cash and cash equivalents: ₱2,000,000. Treasury shares are excluded because they are contra equity accounts representing repurchased stock. The bond sinking fund is excluded because it is restricted for the long term purpose of retiring bonds." } },
  { "FAR-CashAndCashEq-020": { "subject": "FAR", "topic": "Cash and Cash Equivalents", "subtopic": "Adjustments for Excluded Items", "type": "Problem Solving", "competency": "Apply", "question": "On December 31, a company unadjusted cash balance was ₱2,500,000. A review revealed the following inclusions: travel advances ₱50,000; an unreleased check payable to a supplier ₱200,000; and a customer check marked DAIF by the bank ₱150,000. What is the correct cash balance?", "solution": 2500000, "explanation": "Unadjusted cash balance: ₱2,500,000 - Travel advances: 50,000 + Undelivered check: 200,000 - Customer NSF check: 150,000 = Correct cash balance: ₱2,500,000. Travel advances are excluded because they are receivables owed by employees. The undelivered check is added back because physical transmission is required for payment consummation. The DAIF check is deducted because the cash collection failed and must be restored to receivables." } },
  { "FAR-CashAndCashEq-021": { "subject": "FAR", "topic": "Cash and Cash Equivalents", "subtopic": "Cash on Hand Components", "type": "Problem Solving", "competency": "Analyze", "question": "An unadjusted cash count yielded ₱500,000. This includes: coins and bills ₱150,000; manager check ₱50,000; traveler check ₱40,000; customer postdated check ₱60,000; customer NSF check ₱30,000; unreplenished expense vouchers ₱20,000; employee IOUs ₱10,000; and an unreleased company check payable to a supplier for ₱140,000. Calculate the correct cash on hand.", "solution": 520000, "explanation": "Unadjusted cash balance: ₱500,000 - Customer postdated check: 60,000 - Customer NSF check: 30,000 - Unreplenished expense vouchers: 20,000 - Employee IOUs: 10,000 + Unreleased company check: 140,000 = Correct cash balance: ₱520,000. Customer postdated checks and NSF checks are invalid for cash and revert to receivables. Vouchers and IOUs represent expenses and advances. The unreleased company check is added back because the payment is not consummated until the instrument is physically delivered to the payee." } },
  { "FAR-CashAndCashEq-022": { "subject": "FAR", "topic": "Cash and Cash Equivalents", "subtopic": "Bank Overdrafts and Restrictions", "type": "Problem Solving", "competency": "Analyze", "question": "A firm holds the following accounts: Bank A checking ₱1,000,000; Bank A savings ₱500,000; Bank B time deposit ₱400,000; Bank B overdraft ₱200,000; Bank C checking legally restricted for a noncurrent loan ₱300,000; Bank D checking ₱800,000; Bank D overdraft ₱150,000. Compute the total cash and cash equivalents.", "solution": 2350000, "explanation": "Bank A checking: ₱1,000,000 + Bank A savings: 500,000 + Bank B time deposit: 400,000 - Bank B overdraft: 200,000 + Bank D checking: 800,000 - Bank D overdraft: 150,000 = Total cash and cash equivalents: ₱2,350,000. Overdrafts in Bank B and Bank D are offset against the positive balances in those exact same banks due to legal compensation rules. The checking account in Bank C is excluded because it is legally restricted to settle a noncurrent liability." } },
  { "FAR-CashAndCashEq-023": { "subject": "FAR", "topic": "Cash and Cash Equivalents", "subtopic": "Classification of Cash Equivalents", "type": "Problem Solving", "competency": "Analyze", "question": "Evaluate these investments for cash equivalent classification: One year Treasury bill purchased two months before maturity ₱1,000,000; Six month Time deposit purchased three months before maturity ₱800,000; Ninety day Commercial paper purchased forty five days before maturity ₱600,000; One hundred twenty day Treasury bill purchased one hundred days before maturity ₱500,000.", "solution": 2400000, "explanation": "One year Treasury bill purchased two months before maturity: ₱1,000,000 + Six month Time deposit purchased three months before maturity: 800,000 + Ninety day Commercial paper: 600,000 = Total cash equivalents: ₱2,400,000. The one hundred twenty day treasury bill is excluded because it was acquired more than three months before its maturity date. The standard explicitly states that classification depends solely on the three month rule evaluated from the date of acquisition, regardless of the original life of the instrument." } },
  { "FAR-CashAndCashEq-024": { "subject": "FAR", "topic": "Cash and Cash Equivalents", "subtopic": "Compensating Balances", "type": "Problem Solving", "competency": "Analyze", "question": "An unadjusted bank balance of ₱5,000,000 includes a legally restricted compensating balance for a short term loan of ₱500,000, a legally restricted compensating balance for a long term loan of ₱800,000, and an unrestricted compensating balance for a short term loan of ₱400,000. Calculate the correct cash in bank.", "solution": 3700000, "explanation": "Unadjusted bank balance: ₱5,000,000 - Legally restricted balance for short term loan: 500,000 - Legally restricted balance for long term loan: 800,000 = Correct cash in bank: ₱3,700,000. Legally restricted compensating balances are entirely excluded from cash regardless of the term of the related loan because they are blocked from operational use. The unrestricted compensating balance remains fully part of cash because no legal agreement prevents its withdrawal." } },
  { "FAR-CashAndCashEq-025": { "subject": "FAR", "topic": "Cash and Cash Equivalents", "subtopic": "Window Dressing Adjustments", "type": "Problem Solving", "competency": "Analyze", "question": "The cash book was held open until January five. The unadjusted December balance is ₱4,500,000. January cash receipts of ₱600,000 were recorded as December receipts. January cash disbursements of ₱400,000 were recorded as December disbursements. Additionally, unreleased checks actually drawn in December amount to ₱300,000. Compute the adjusted cash balance.", "solution": 4600000, "explanation": "Unadjusted cash balance: ₱4,500,000 - January receipts recorded in December: 600,000 + January disbursements recorded in December: 400,000 + Unreleased checks drawn in December: 300,000 = Adjusted cash balance: ₱4,600,000. Receipts and disbursements occurring after the reporting period must be reversed to properly reflect the true cutoff date. Unreleased checks are added back because cash is not legally reduced until the check is physically delivered to the payee." } },
  { "FAR-CashAndCashEq-026": { "subject": "FAR", "topic": "Cash and Cash Equivalents", "subtopic": "Foreign Currency Translation", "type": "Problem Solving", "competency": "Apply", "question": "A company holds a US Dollar account of 100,000 dollars at a historical rate of ₱50 per dollar, and a Euro account of 50,000 euros at a historical rate of ₱60 per euro. The current exchange rates on December 31 are ₱56 per dollar and ₱62 per euro. Calculate the adjusted total cash balance in Philippine Pesos.", "solution": 8700000, "explanation": "US Dollar account at current rate: ₱5,600,000 + Euro account at current rate: 3,100,000 = Adjusted cash balance: ₱8,700,000. Foreign currency bank accounts are monetary assets that must be restated using the closing exchange rate prevailing at the reporting date." } },
  { "FAR-CashAndCashEq-027": { "subject": "FAR", "topic": "Cash and Cash Equivalents", "subtopic": "Petty Cash Fund", "type": "Problem Solving", "competency": "Analyze", "question": "An imprest petty cash fund was established at ₱50,000. A year end count reveals: Coins and bills ₱12,000; Paid expense vouchers ₱30,000; Employee IOUs ₱5,000; and a check drawn to replenish the fund ₱2,000. What is the amount of the petty cash shortage?", "solution": 1000, "explanation": "Imprest petty cash fund amount: ₱50,000 - Coins and bills: 12,000 - Paid expense vouchers: 30,000 - Employee IOUs: 5,000 - Replenishment check: 2,000 = Petty cash shortage: ₱1,000. The shortage is computed by deducting the total sum of all valid physical items and documents found during the cash count from the legally established imprest accountability." } },
  { "FAR-CashAndCashEq-028": { "subject": "FAR", "topic": "Cash and Cash Equivalents", "subtopic": "Classification of Specific Funds", "type": "Problem Solving", "competency": "Analyze", "question": "Determine the cash to be reported for current operations given these funds: Payroll fund ₱400,000; Interest fund ₱200,000; Dividend fund ₱300,000; Tax fund ₱100,000; and a Sinking fund for bonds maturing in five years ₱1,000,000.", "solution": 1000000, "explanation": "Payroll fund: ₱400,000 + Interest fund: 200,000 + Dividend fund: 300,000 + Tax fund: 100,000 = Total cash for current operations: ₱1,000,000. Funds set aside specifically for the payment of current operating liabilities are included in cash. The sinking fund is strictly excluded because it is earmarked for the settlement of a noncurrent liability." } },
  { "FAR-CashAndCashEq-029": { "subject": "FAR", "topic": "Cash and Cash Equivalents", "subtopic": "Adjusted Bank Balance", "type": "Problem Solving", "competency": "Analyze", "question": "The unadjusted ledger balance is ₱3,620,000. A bank reconciliation reveals a note collected by the bank of ₱300,000, a bank service charge of ₱20,000, and a book error where a company payment was erroneously overstated by ₱100,000. Calculate the adjusted cash balance.", "solution": 4000000, "explanation": "Unadjusted ledger balance: ₱3,620,000 + Note collected by bank: 300,000 - Bank service charge: 20,000 + Book error overstating disbursement: 100,000 = Adjusted cash balance: ₱4,000,000. Valid adjustments to the internal book balance include bank credits not yet recorded, bank debits not yet recorded, and the correction of internal company errors. Overstating a payment means too much was deducted initially, so the excess must be added back." } },
  { "FAR-CashAndCashEq-030": { "subject": "FAR", "topic": "Cash and Cash Equivalents", "subtopic": "Bank Overdrafts Offsetting", "type": "Problem Solving", "competency": "Analyze", "question": "A company holds accounts across multiple institutions: Bank A checking ₱1,200,000; Bank A overdraft ₱300,000; Bank B checking ₱500,000; Bank C overdraft ₱150,000; Bank D legally restricted account ₱400,000. What is the total reportable cash in bank?", "solution": 1400000, "explanation": "Bank A checking: ₱1,200,000 - Bank A overdraft: 300,000 + Bank B checking: 500,000 = Total cash in bank: ₱1,400,000. The overdraft in Bank A is legally offset against the positive balance because they reside in the same financial institution. The overdraft in Bank C cannot be offset and is reported as a separate current liability, while the legally restricted account in Bank D is excluded from cash." } },
  { "FAR-CashAndCashEq-031": { "subject": "FAR", "topic": "Cash and Cash Equivalents", "subtopic": "Checkbook Adjustments", "type": "Problem Solving", "competency": "Analyze", "question": "An unadjusted cash balance is ₱2,500,000. Included as deductions are: an undelivered check ₱200,000; a postdated check drawn ₱150,000; a check held at payee request ₱100,000; and a check lost in the mail ₱50,000. Compute the adjusted cash balance.", "solution": 2950000, "explanation": "Unadjusted cash balance: ₱2,500,000 + Undelivered check: 200,000 + Postdated check drawn: 150,000 + Check held at payee request: 100,000 = Adjusted cash balance: ₱2,950,000. Undelivered checks, postdated checks drawn, and checks deliberately held from encashment do not constitute valid completed payments at year end and must be restored to the cash ledger. The check lost in the mail was successfully released and remains an outstanding check rather than a book adjustment." } },
  { "FAR-CashAndCashEq-032": { "subject": "FAR", "topic": "Cash and Cash Equivalents", "subtopic": "Petty Cash Fund", "type": "Problem Solving", "competency": "Analyze", "question": "Determine total cash and cash equivalents: Cash in bank ₱1,500,000; Money market placement ₱500,000; Petty cash fund ledger balance ₱30,000 consisting of ₱10,000 coins and bills, ₱15,000 unreplenished vouchers, and ₱5,000 employee IOUs.", "solution": 2010000, "explanation": "Cash in bank: ₱1,500,000 + Money market placement: 500,000 + Petty cash coins and bills: 10,000 = Total cash and cash equivalents: ₱2,010,000. Only the actual physical currency and bills found in the petty cash box are classified as cash. The unreplenished vouchers and employee IOUs must be reclassified to their respective expense and receivable accounts." } },
  { "FAR-CashAndCashEq-033": { "subject": "FAR", "topic": "Cash and Cash Equivalents", "subtopic": "Short Term Investments", "type": "Problem Solving", "competency": "Analyze", "question": "Select the valid cash equivalents: Ninety day Treasury bill ₱800,000; Sixty day Time deposit ₱500,000; Ordinary equity shares intended for trading ₱300,000; Redeemable preference shares purchased two months before mandatory redemption ₱400,000. Calculate total cash equivalents.", "solution": 1700000, "explanation": "Ninety day Treasury bill: ₱800,000 + Sixty day Time deposit: 500,000 + Redeemable preference shares: 400,000 = Total cash equivalents: ₱1,700,000. Redeemable preference shares containing a mandatory redemption date acquired within three months of that date act like debt instruments and qualify as cash equivalents. Ordinary equity shares are completely excluded because they represent permanent ownership." } },
  { "FAR-CashAndCashEq-034": { "subject": "FAR", "topic": "Cash and Cash Equivalents", "subtopic": "Restricted Funds", "type": "Problem Solving", "competency": "Analyze", "question": "Identify total cash given the following accounts: General checking ₱2,000,000; Payroll bank account ₱600,000; VAT bank account ₱400,000; Escrow account for a legal dispute ₱500,000; Cash frozen in a closed bank ₱200,000.", "solution": 3000000, "explanation": "General checking account: ₱2,000,000 + Payroll bank account: 600,000 + VAT bank account: 400,000 = Total cash and cash equivalents: ₱3,000,000. Accounts strictly designated for the payment of current operating liabilities like payroll and taxes remain classified as cash. The escrow account is excluded due to legal contingencies, and cash in a closed bank is reclassified as a receivable." } },
  { "FAR-CashAndCashEq-035": { "subject": "FAR", "topic": "Cash and Cash Equivalents", "subtopic": "Cash Count Valuation", "type": "Problem Solving", "competency": "Analyze", "question": "A cash count totaling ₱150,000 includes: ₱50,000 coins and bills; a ₱40,000 manager check; a ₱30,000 customer postdated check; a ₱20,000 customer NSF check; and a ₱10,000 stale customer check. Determine the correct cash on hand.", "solution": 90000, "explanation": "Coins and bills: ₱50,000 + Manager check: 40,000 = Correct cash on hand: ₱90,000. The postdated check, NSF check, and stale check are excluded because they are practically uncashable instruments at the reporting date and must be formally reverted to accounts receivable." } },
  { "FAR-CashAndCashEq-036": { "subject": "FAR", "topic": "Cash and Cash Equivalents", "subtopic": "Classification of Cash Equivalents", "type": "Problem Solving", "competency": "Analyze", "question": "A company holds four treasury bills. Bill A was purchased two months before maturity for ₱500,000. Bill B was purchased three months before maturity for ₱400,000. Bill C is a standard ninety day bill for ₱300,000. Bill D was purchased five months before maturity for ₱200,000. Calculate cash equivalents.", "solution": 1200000, "explanation": "Treasury bill purchased two months before maturity: ₱500,000 + Treasury bill purchased three months before maturity: 400,000 + Ninety day treasury bill: 300,000 = Total cash equivalents: ₱1,200,000. The primary criterion is strictly the date of acquisition, meaning any instrument acquired three months or less before its maturity uniquely qualifies. The treasury bill purchased five months before maturity fails this test and is booked as a short term investment." } },
  { "FAR-CashAndCashEq-037": { "subject": "FAR", "topic": "Cash and Cash Equivalents", "subtopic": "Short Term Investments", "type": "Problem Solving", "competency": "Analyze", "question": "An unadjusted cash balance of ₱6,000,000 includes a ₱1,000,000 time deposit originally placed for one year but now maturing in two months, and a ₱500,000 legally restricted compensating balance. Calculate the correct cash and cash equivalents.", "solution": 4500000, "explanation": "Unadjusted cash balance: ₱6,000,000 - Time deposit maturing in two months: 1,000,000 - Restricted compensating balance: 500,000 = Correct cash and cash equivalents: ₱4,500,000. The time deposit is completely excluded because its original term established at the date of acquisition was one year, prohibiting it from becoming a cash equivalent merely because its remaining term is now short. The restricted compensating balance is likewise excluded." } },
  { "FAR-CashAndCashEq-038": { "subject": "FAR", "topic": "Cash and Cash Equivalents", "subtopic": "Bank Overdrafts Offsetting", "type": "Problem Solving", "competency": "Analyze", "question": "Evaluate these accounts: Checking account A ₱800,000; Checking account B in a different bank overdraft ₱100,000; Savings account A ₱300,000; Savings account B in a different bank ₱150,000; Payroll account A ₱400,000. Compute total cash in bank.", "solution": 1650000, "explanation": "Checking account A: ₱800,000 + Savings account A: 300,000 + Savings account B: 150,000 + Payroll account A: 400,000 = Total cash in bank: ₱1,650,000. The overdraft in Bank B strictly cannot be offset against any of the positive accounts in Bank A because the legal right of compensation does not exist between completely separate and independent financial institutions." } },
  { "FAR-CashAndCashEq-039": { "subject": "FAR", "topic": "Cash and Cash Equivalents", "subtopic": "Adjusted Bank Balance", "type": "Problem Solving", "competency": "Analyze", "question": "The unadjusted ledger balance is ₱2,800,000. The bank reconciliation shows outstanding checks of ₱400,000 which includes a certified check of ₱50,000. The bank collected a note of ₱110,000. A book error recorded a ₱100,000 collection as ₱10,000. Calculate the adjusted cash balance.", "solution": 3000000, "explanation": "Unadjusted ledger balance: ₱2,800,000 + Note collected by bank: 110,000 + Book error understating collection: 90,000 = Adjusted cash balance: ₱3,000,000. The certified check is an adjusting item for the bank statement balance, not the ledger, and is uniquely excluded from normal outstanding checks because the bank deducts it immediately upon certification. The internal book error understated the collection by ninety thousand, requiring an addition." } },
  { "FAR-CashAndCashEq-040": { "subject": "FAR", "topic": "Cash and Cash Equivalents", "subtopic": "Comprehensive Cash Adjustments", "type": "Problem Solving", "competency": "Analyze", "question": "Compute cash and cash equivalents: Cash on hand ₱200,000 including a ₱50,000 postdated check; Cash in Bank A ₱1,000,000 including an unrestricted compensating balance of ₱150,000; Cash in Bank B ₱500,000 including a legally restricted compensating balance of ₱200,000; Sixty day treasury bill ₱800,000; One hundred twenty day treasury bill ₱400,000.", "solution": 2250000, "explanation": "Cash on hand excluding postdated check: ₱150,000 + Cash in bank A: 1,000,000 + Cash in bank B excluding restricted balance: 300,000 + Sixty day treasury bill: 800,000 = Total cash and cash equivalents: ₱2,250,000. The unrestricted compensating balance remains in cash, while the legally restricted balance is removed. The postdated check is reclassified as a receivable, and the one hundred twenty day treasury bill fails the acquisition maturity test." } },
  { "FAR-CashAndCashEq-041": { "subject": "FAR", "topic": "Cash and Cash Equivalents", "subtopic": "Comprehensive Cash Equivalents", "type": "Problem Solving", "competency": "Analyze", "question": "The trial balance shows: Bank One checking ₱2,500,000; Bank One overdraft ₱300,000; Bank Two checking ₱1,200,000; Bank Two overdraft ₱1,500,000; Ninety day money market placement ₱800,000; One hundred twenty day treasury bill purchased sixty days before maturity ₱500,000; Sinking fund for bond retirement ₱1,000,000. Compute total cash and cash equivalents.", "solution": 4700000, "explanation": "Bank One checking: ₱2,500,000 - Bank One overdraft: 300,000 + Bank Two checking: 1,200,000 + Ninety day money market placement: 800,000 + Treasury bill purchased sixty days before maturity: 500,000 = Total cash and cash equivalents: ₱4,700,000. The overdraft in Bank One is offset because it is in the same bank. The Bank Two overdraft cannot offset the positive checking account in Bank One and is reported as a current liability. The treasury bill is a cash equivalent because it was purchased within three months of its exact maturity date. The sinking fund is strictly excluded as it is a noncurrent asset designated for long term debt." } },
  { "FAR-CashAndCashEq-042": { "subject": "FAR", "topic": "Cash and Cash Equivalents", "subtopic": "Petty Cash Imprest System", "type": "Problem Solving", "competency": "Analyze", "question": "A petty cash fund is established at ₱50,000. A surprise count reveals: Currency ₱5,000; Replenishment check drawn to custodian ₱15,000; Accommodated customer check ₱4,000; Postdated employee check ₱6,000; Unreplenished paid vouchers ₱18,000; Counterfeit bill ₱1,000. What is the correct petty cash balance to be reported?", "solution": 240000, "explanation": "Currency and coins: ₱5,000 + Replenishment check: 15,000 + Accommodated customer check: 4,000 = Correct petty cash fund: ₱24,000. The accommodated customer check is valid cash as it is an instrument ready for immediate deposit. The postdated employee check is a receivable. Paid vouchers are unrecorded expenses. The counterfeit bill is worthless and represents a cash shortage." } },
  { "FAR-CashAndCashEq-043": { "subject": "FAR", "topic": "Cash and Cash Equivalents", "subtopic": "Window Dressing Receipts", "type": "Problem Solving", "competency": "Analyze", "question": "The cash book was held open until January four. The unadjusted December cash balance is ₱6,200,000. January cash collections of ₱800,000 were recorded as December receipts. Included in the December collections is a customer check of ₱150,000 dated January ten. Calculate the adjusted cash balance.", "solution": 5250000, "explanation": "Unadjusted cash balance: ₱6,200,000 - January collections recorded in December: 800,000 - Postdated customer check: 150,000 = Adjusted cash balance: ₱5,250,000. Keeping the cash book open artificially inflates cash so the subsequent period collections must be reversed. The postdated customer check received in December is not valid cash until its date arrives and must be reverted to accounts receivable." } },
  { "FAR-CashAndCashEq-044": { "subject": "FAR", "topic": "Cash and Cash Equivalents", "subtopic": "Window Dressing Disbursements", "type": "Problem Solving", "competency": "Analyze", "question": "The cash ledger balance is ₱4,800,000. January cash disbursements of ₱500,000 were recorded as December payments to improve the current ratio. Furthermore, unreleased checks physically drawn and recorded in December amount to ₱350,000. Compute the adjusted cash balance.", "solution": 5650000, "explanation": "Unadjusted cash balance: ₱4,800,000 + January disbursements recorded in December: 500,000 + Unreleased checks drawn in December: 350,000 = Adjusted cash balance: ₱5,650,000. Payments made in January but recorded in December must be added back to correct the early cutoff. Unreleased checks are also added back because cash is not legally transferred until the instrument is physically delivered to the payee." } },
  { "FAR-CashAndCashEq-045": { "subject": "FAR", "topic": "Cash and Cash Equivalents", "subtopic": "Foreign Currency Translation", "type": "Problem Solving", "competency": "Analyze", "question": "An unadjusted cash balance of ₱8,000,000 includes a US Dollar account of one hundred thousand dollars recorded at a historical rate of ₱52 per dollar, and a restricted foreign escrow account of ₱1,000,000. The exchange rate on December 31 is ₱56 per dollar. What is the adjusted cash balance?", "solution": 7400000, "explanation": "Unadjusted cash balance: ₱8,000,000 + Foreign exchange gain on translation: 400,000 - Restricted foreign escrow account: 1,000,000 = Adjusted cash balance: ₱7,400,000. The US dollar account is a monetary asset that must be restated at the closing rate yielding a four hundred thousand peso unrealized gain. The escrow account is deducted because it is restricted and unavailable for current operations." } },
  { "FAR-CashAndCashEq-046": { "subject": "FAR", "topic": "Cash and Cash Equivalents", "subtopic": "Compensating Balances and Credit Lines", "type": "Problem Solving", "competency": "Analyze", "question": "Bank balance is ₱9,500,000. This includes a legally restricted compensating balance of ₱1,500,000 against a short term loan, an informal compensating balance of ₱500,000 against a long term loan, and a legally restricted balance of ₱1,000,000 maintained for an unused credit line. Compute the correct cash in bank.", "solution": 7000000, "explanation": "Unadjusted bank balance: ₱9,500,000 - Restricted compensating balance for short term loan: 1,500,000 - Restricted compensating balance for unused credit line: 1,000,000 = Correct cash in bank: ₱7,000,000. Legally restricted balances are excluded regardless of whether they relate to short term loans long term loans or unused credit facilities. Informal balances remain part of cash because they lack binding legal restrictions." } },
  { "FAR-CashAndCashEq-047": { "subject": "FAR", "topic": "Cash and Cash Equivalents", "subtopic": "Bank Reconciliation Adjustments", "type": "Problem Solving", "competency": "Analyze", "question": "The ledger balance is ₱5,400,000. Reconciling items include: Bank service charge ₱15,000; NSF check ₱85,000; Note collected by bank including interest ₱350,000; Outstanding checks ₱600,000 including a certified check of ₱100,000; and a book error where a ₱40,000 payment was recorded as ₱4,000. Calculate the adjusted cash balance.", "solution": 5614000, "explanation": "Ledger balance: ₱5,400,000 - Bank service charge: 15,000 - NSF check: 85,000 + Note collected by bank: 350,000 - Book error understating payment: 36,000 = Adjusted cash balance: ₱5,614,000. Outstanding checks and certified checks affect the bank statement balance not the book balance. The book error understated the disbursement by thirty six thousand so this amount must be further deducted from the ledger." } },
  { "FAR-CashAndCashEq-048": { "subject": "FAR", "topic": "Cash and Cash Equivalents", "subtopic": "Specific Fund Classifications", "type": "Problem Solving", "competency": "Analyze", "question": "A company lists the following funds: General payroll fund ₱800,000; Travel advance fund ₱150,000; Dividend payment fund ₱600,000; Sinking fund ₱2,000,000; Tax fund ₱400,000; Preference share redemption fund ₱1,500,000. What amount is included in cash and cash equivalents?", "solution": 1800000, "explanation": "General payroll fund: ₱800,000 + Dividend payment fund: 600,000 + Tax fund: 400,000 = Total cash and cash equivalents: ₱1,800,000. Funds strictly for current operating liabilities are cash. Travel advances are receivables. Sinking funds and preference share redemption funds are noncurrent investments set aside for long term obligations." } },
  { "FAR-CashAndCashEq-049": { "subject": "FAR", "topic": "Cash and Cash Equivalents", "subtopic": "Short Term Investments and Equities", "type": "Problem Solving", "competency": "Analyze", "question": "Evaluate these items: Ninety day Commercial paper ₱1,200,000; One hundred eighty day Treasury bill bought ninety days before maturity ₱800,000; Equity trading securities ₱500,000; Redeemable preference shares acquired two months before mandatory redemption ₱700,000. Calculate total cash equivalents.", "solution": 2700000, "explanation": "Ninety day Commercial paper: ₱1,200,000 + Treasury bill bought ninety days before maturity: 800,000 + Redeemable preference shares: 700,000 = Total cash equivalents: ₱2,700,000. Equity trading securities are always excluded as they have no maturity date. Redeemable preference shares act like debt and qualify if acquired within three months of their fixed redemption date." } },
  { "FAR-CashAndCashEq-050": { "subject": "FAR", "topic": "Cash and Cash Equivalents", "subtopic": "Comprehensive Bank Accounts", "type": "Problem Solving", "competency": "Analyze", "question": "Determine reportable cash: Bank A current account ₱2,500,000; Bank A frozen account ₱300,000; Bank B savings ₱1,800,000; Bank B overdraft ₱400,000; Bank C current account ₱900,000; Bank C closed bank account ₱200,000. Calculate total cash and cash equivalents.", "solution": 4800000, "explanation": "Bank A current account: ₱2,500,000 + Bank B savings: 1,800,000 - Bank B overdraft: 400,000 + Bank C current account: 900,000 = Total cash and cash equivalents: ₱4,800,000. Bank B overdraft is properly offset against the savings account in the same bank. Frozen accounts and closed bank accounts are excluded from cash because the funds cannot be legally accessed and are reclassified as receivables." } },
  { "FAR-CashAndCashEq-051": { "subject": "FAR", "topic": "Cash and Cash Equivalents", "subtopic": "Postdated and Stale Checks", "type": "Problem Solving", "competency": "Analyze", "question": "A cash count shows ₱800,000. Inclusions: Customer postdated check ₱120,000; Company check postdated to a supplier ₱90,000; Customer check dated ten months ago ₱50,000; Certified customer check ₱150,000; Manager check ₱200,000. What is the correct cash on hand?", "solution": 630000, "explanation": "Unadjusted cash count: ₱800,000 - Customer postdated check: 120,000 - Customer check dated ten months ago: 50,000 = Correct cash on hand: ₱630,000. Customer postdated checks and stale checks over six months old are invalid for encashment and revert to receivables. The company postdated check drawn is not part of the physical count of cash on hand so it requires no adjustment here. Certified checks and manager checks are fully valid cash instruments." } },
  { "FAR-CashAndCashEq-052": { "subject": "FAR", "topic": "Cash and Cash Equivalents", "subtopic": "Investment Maturity Rules", "type": "Problem Solving", "competency": "Analyze", "question": "A company holds: Two year Treasury note purchased one month before maturity ₱1,500,000; Ninety day Time deposit placed forty five days ago ₱600,000; One hundred twenty day Commercial paper purchased today ₱400,000. Calculate total cash equivalents.", "solution": 2100000, "explanation": "Two year Treasury note purchased one month before maturity: ₱1,500,000 + Ninety day Time deposit: 600,000 = Total cash equivalents: ₱2,100,000. The long term treasury note qualifies because the sole test is the remaining maturity from the date of acquisition. The one hundred twenty day commercial paper is excluded because its maturity from the acquisition date exceeds three months." } },
  { "FAR-CashAndCashEq-053": { "subject": "FAR", "topic": "Cash and Cash Equivalents", "subtopic": "Petty Cash Accountability", "type": "Problem Solving", "competency": "Analyze", "question": "An imprest fund is ₱100,000. The count reveals: Bills ₱15,000; Coins ₱3,000; Check to replenish ₱30,000; Vouchers for transportation ₱18,000; Vouchers for supplies ₱25,000; Employee advances ₱12,000. Calculate the cash shortage or overage.", "solution": 3000, "explanation": "Total physical items and documents: ₱103,000 - Imprest petty cash fund amount: 100,000 = Petty cash overage: ₱3,000. By summing all the valid accountability items including coins bills the replenishment check expense vouchers and employee advances the total exceeds the established fund balance indicating an overage." } },
  { "FAR-CashAndCashEq-054": { "subject": "FAR", "topic": "Cash and Cash Equivalents", "subtopic": "Bank Error Adjustments", "type": "Problem Solving", "competency": "Analyze", "question": "The unadjusted book balance is ₱4,200,000. The bank erroneously credited the company account for ₱300,000 belonging to another client. The bank erroneously charged the company ₱150,000 for a check drawn by a different firm. A company check for ₱50,000 was recorded in the books as ₱500,000. Calculate the adjusted book balance.", "solution": 4650000, "explanation": "Unadjusted book balance: ₱4,200,000 + Book error overstating disbursement: 450,000 = Adjusted book balance: ₱4,650,000. Bank errors affect the bank statement balance during reconciliation but do not require adjustments to the internal company ledger. The book error originally deducted too much cash so the excess difference of four hundred fifty thousand must be added back." } },
  { "FAR-CashAndCashEq-055": { "subject": "FAR", "topic": "Cash and Cash Equivalents", "subtopic": "Multiple Currency Translation", "type": "Problem Solving", "competency": "Analyze", "question": "A ledger shows ₱10,000,000. This includes a Yen account of two million yen booked at ₱0.40 per yen. Current rate is ₱0.45 per yen. It also includes a legally restricted Pound account of fifty thousand pounds booked at ₱60 per pound. Current rate is ₱65 per pound. Calculate adjusted cash and cash equivalents.", "solution": 7100000, "explanation": "Unadjusted ledger balance: ₱10,000,000 + Yen account foreign exchange gain: 100,000 - Restricted Pound account original book value: 3,000,000 = Adjusted cash and cash equivalents: ₱7,100,000. The Yen account is translated at the closing rate resulting in a gain. The Pound account is completely deducted because its legal restriction disqualifies it from being reported as cash regardless of its current exchange valuation." } },
  { "FAR-CashAndCashEq-056": { "subject": "FAR", "topic": "Cash and Cash Equivalents", "subtopic": "Mixed Checks and Drafts", "type": "Problem Solving", "competency": "Analyze", "question": "Compute cash on hand: Cash count ₱1,200,000. Includes: Bank draft ₱150,000; Postal money order ₱50,000; Customer check returned due to insufficient funds ₱80,000; Unreleased check drawn to pay taxes ₱200,000; Postdated check received from a client ₱120,000.", "solution": 1000000, "explanation": "Unadjusted cash count: ₱1,200,000 - Customer NSF check: 80,000 - Postdated check received: 120,000 = Correct cash on hand: ₱1,000,000. Bank drafts and postal money orders are valid cash items. NSF checks and postdated checks received are excluded and reverted to receivables. The unreleased check drawn is an internal book adjustment and does not affect the physical count of cash on hand." } },
  { "FAR-CashAndCashEq-057": { "subject": "FAR", "topic": "Cash and Cash Equivalents", "subtopic": "Window Dressing Complete Reversal", "type": "Problem Solving", "competency": "Analyze", "question": "The December cash balance is ₱5,500,000. It was discovered that the cash receipts journal was kept open until January 8 including ₱1,200,000 of January collections. The cash disbursements journal was kept open until January 5 including ₱900,000 of January payments. Calculate the true December 31 cash balance.", "solution": 5200000, "explanation": "Unadjusted cash balance: ₱5,500,000 - January collections recorded in December: 1,200,000 + January payments recorded in December: 900,000 = True December cash balance: ₱5,200,000. To establish the correct financial position at year end all transactions that actually occurred in the subsequent period must be fully reversed regardless of when they were recorded." } },
  { "FAR-CashAndCashEq-058": { "subject": "FAR", "topic": "Cash and Cash Equivalents", "subtopic": "Compensating Balance on Unused Credit", "type": "Problem Solving", "competency": "Analyze", "question": "A company holds ₱8,000,000 in a checking account. The bank requires a ten percent compensating balance against a ₱5,000,000 outstanding loan and a five percent compensating balance against a ₱10,000,000 unused line of credit. Both are legally restricted. What is the reportable cash in bank?", "solution": 7000000, "explanation": "Total checking account: ₱8,000,000 - Restricted balance for outstanding loan: 500,000 - Restricted balance for unused credit line: 500,000 = Reportable cash in bank: ₱7,000,000. Any legally restricted compensating balance whether tied to an actively borrowed amount or merely an available credit facility must be excluded from cash and cash equivalents." } },
  { "FAR-CashAndCashEq-059": { "subject": "FAR", "topic": "Cash and Cash Equivalents", "subtopic": "Time Deposits and Placements", "type": "Problem Solving", "competency": "Analyze", "question": "Evaluate total cash equivalents: Sixty day Time deposit ₱1,500,000; One hundred twenty day Time deposit broken into two periods with thirty days remaining ₱800,000; Ninety day Money market placement ₱1,200,000; Callable preference shares ₱500,000.", "solution": 2700000, "explanation": "Sixty day Time deposit: ₱1,500,000 + Ninety day Money market placement: 1,200,000 = Total cash equivalents: ₱2,700,000. The one hundred twenty day time deposit is excluded because its original acquisition term was over three months. Callable preference shares are excluded because the issuer has the option to call them meaning the investor has no fixed guaranteed maturity date." } },
  { "FAR-CashAndCashEq-060": { "subject": "FAR", "topic": "Cash and Cash Equivalents", "subtopic": "Ultimate Comprehensive Adjustments", "type": "Problem Solving", "competency": "Analyze", "question": "Determine correct cash and cash equivalents: Unadjusted ledger ₱15,000,000. Includes: Bank A overdraft ₱500,000 offset against Bank B positive balance; Legally restricted balance ₱1,000,000; Sinking fund ₱2,500,000; Postdated check received ₱400,000; Unreleased check drawn ₱600,000; One hundred eighty day commercial paper purchased sixty days before maturity ₱800,000.", "solution": 12000000, "explanation": "Unadjusted ledger balance: ₱15,000,000 + Bank A overdraft wrongfully offset: 500,000 - Legally restricted balance: 1,000,000 - Sinking fund: 2,500,000 - Postdated check received: 400,000 + Unreleased check drawn: 600,000 - One hundred eighty day commercial paper: 200,000 = Correct cash and cash equivalents: ₱12,000,000. The Bank A overdraft must be added back to cash because it cannot be offset against Bank B. Restricted balances and sinking funds are excluded. Postdated checks received are receivables. Unreleased checks drawn are restored to cash. The commercial paper is already included in the unadjusted balance but must be excluded because it is an investment not a cash equivalent." } }

];
